`collections.UserDict` does not loose instance attributes. Example:

```python
from collections import UserDict
import jsonpickle

class A(UserDict):
    def __init__(self, *args, **kwargs):
        self.a = 1
        super().__init__(*args, **kwargs)
    
    def set_a(self, v):
        self.a = v

    def get_a(self):
        return self.a

x = A()
print(x)  # {}
print(x.get_a())  # 1
print(jsonpickle.encode(x))  # {"a": 1, "data": {}, "py/object": "__main__.A"}

y = jsonpickle.decode(jsonpickle.encode(x))
print(y)  # {}
print(y.get_a())  # 1
```

